module Admin::DashboardHelper
  def admin_sidebar_link(label, path, icon)
    active = request.path.start_with?(path)
    active_class = active ? "admin-sidebar-link active" : "admin-sidebar-link"
    link_to path, class: active_class do
      raw(admin_icon(icon) + " <span>#{label}</span>")
    end
  end

